namespace sv_27bde7606311449986d8e654255cc893.Models;

public class WizardState
{
    // Step 1: Personal Info
    public string FullName { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2: Experience
    public List<JobHistoryEntry> JobHistory { get; set; } = [];

    // Step 3: References
    public List<ReferenceContact> References { get; set; } = [];

    public bool IsStep1Complete => !string.IsNullOrWhiteSpace(FullName) && !string.IsNullOrWhiteSpace(Email);
    public bool IsStep2Complete => JobHistory.Count > 0;
    public bool IsStep3Complete => References.Count > 0;
}

public class JobHistoryEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Duration { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
}

using System.Collections.Concurrent;
using sv_27bde7606311449986d8e654255cc893.Models;

namespace sv_27bde7606311449986d8e654255cc893.Services;

/// <summary>
/// Singleton service that stores wizard state per session.
/// Accessible from both static SSR (layout) and interactive server components (pages).
/// </summary>
public class WizardStateService
{
    private readonly ConcurrentDictionary<string, WizardState> _states = new();

    public WizardState GetState(string sessionId)
    {
        return _states.GetOrAdd(sessionId, _ => new WizardState());
    }

    public void RemoveState(string sessionId)
    {
        _states.TryRemove(sessionId, out _);
    }
}

namespace sv_27bde7606311449986d8e654255cc893.Services;

/// <summary>
/// Ensures every request has a wizard session cookie so both SSR layout
/// and interactive pages can look up the same WizardState.
/// </summary>
public class WizardSessionMiddleware
{
    private readonly RequestDelegate _next;
    public const string CookieName = "WizardSessionId";

    public WizardSessionMiddleware(RequestDelegate next)
    {
        _next = next;
    }

    public async Task InvokeAsync(HttpContext context)
    {
        if (!context.Request.Cookies.ContainsKey(CookieName))
        {
            var sessionId = Guid.NewGuid().ToString();
            context.Response.Cookies.Append(CookieName, sessionId, new CookieOptions
            {
                HttpOnly = true,
                SameSite = SameSiteMode.Strict,
                MaxAge = TimeSpan.FromHours(4)
            });
            context.Items[CookieName] = sessionId;
        }
        else
        {
            context.Items[CookieName] = context.Request.Cookies[CookieName];
        }

        await _next(context);
    }
}

