    <div class="card-body">
        @if (state.References.Count == 0)
        {
            <p class="text-muted">No references added.</p>
        }
        else
        {
            <table class="table table-sm">
                <thead><tr><th>Name</th><th>Relationship</th><th>Phone</th></tr></thead>
                <tbody>
                    @foreach (var r in state.References)
                    {
                        <tr><td>@r.Name</td><td>@r.Relationship</td><td>@r.Phone</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>
</div>

<div class="d-flex gap-2">
    <a href="/apply/references" class="btn btn-outline-secondary">&larr; Back</a>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
