@layout ApplyLayout
@rendermode InteractiveServer
@inject sv_27bde7606311449986d8e654255cc893.Services.WizardStateService StateService
@inject IHttpContextAccessor HttpContextAccessor
@inject NavigationManager Nav

<h3>References</h3>

@if (_refs.Count > 0)
{
    <table class="table table-sm mb-3">
        <thead>
            <tr><th>Name</th><th>Relationship</th><th>Phone</th><th></th></tr>
        </thead>
        <tbody>
            @foreach (var r in _refs)
            {
                <tr>
                    <td>@r.Name</td>
                    <td>@r.Relationship</td>
                    <td>@r.Phone</td>
                    <td><button class="btn btn-sm btn-outline-danger" @onclick="() => _refs.Remove(r)">Remove</button></td>
                </tr>
            }
        </tbody>
    </table>
}

<div class="card p-3 mb-3">
    <h5>Add Reference</h5>
    <div class="row g-2">
        <div class="col-md-4">
            <input class="form-control" placeholder="Name" @bind="_newName" />
        </div>
        <div class="col-md-4">
            <input class="form-control" placeholder="Relationship" @bind="_newRelationship" />
        </div>
        <div class="col-md-3">
            <input class="form-control" placeholder="Phone" @bind="_newPhone" />
        </div>
        <div class="col-md-1">
            <button class="btn btn-success" @onclick="AddRef">+</button>
        </div>
    </div>
</div>

<div class="d-flex gap-2">
    <a href="/apply/experience" class="btn btn-outline-secondary">&larr; Back</a>
    <button class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    private List<Models.ReferenceContact> _refs = [];
    private string _newName = string.Empty;
    private string _newRelationship = string.Empty;
    private string _newPhone = string.Empty;

    private string GetSessionId() =>
        HttpContextAccessor.HttpContext?.Request.Cookies[
            Services.WizardSessionMiddleware.CookieName] ?? string.Empty;

    protected override void OnInitialized()
    {
        var state = StateService.GetState(GetSessionId());
        _refs = state.References.Select(r => new Models.ReferenceContact
        {
            Name = r.Name, Relationship = r.Relationship, Phone = r.Phone
        }).ToList();
    }

    private void AddRef()
    {
        if (!string.IsNullOrWhiteSpace(_newName))
        {
            _refs.Add(new Models.ReferenceContact
            {
                Name = _newName, Relationship = _newRelationship, Phone = _newPhone
            });
            _newName = _newRelationship = _newPhone = string.Empty;
        }
    }

    private void Next()
    {
        SaveState();
        Nav.NavigateTo("/apply/review");
    }

    private void SaveState()
    {
        var state = StateService.GetState(GetSessionId());
        state.References = _refs.ToList();
    }
}

