@page "/apply/review"
@layout ApplyLayout
@rendermode InteractiveServer
@inject sv_27bde7606311449986d8e654255cc893.Services.WizardStateService StateService
@inject IHttpContextAccessor HttpContextAccessor

<h3>Review Your Application</h3>

@{
    var state = StateService.GetState(GetSessionId());
}

<div class="card mb-3">
    <div class="card-header"><strong>Personal Information</strong></div>
    <div class="card-body">
        <p><strong>Name:</strong> @state.FullName</p>
        <p><strong>Email:</strong> @state.Email</p>
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>Work Experience</strong></div>
    <div class="card-body">
        @if (state.JobHistory.Count == 0)
        {
            <p class="text-muted">No entries added.</p>
        }
        else
        {
            <table class="table table-sm">
                <thead><tr><th>Company</th><th>Title</th><th>Duration</th></tr></thead>
                <tbody>
                    @foreach (var j in state.JobHistory)
                    {
                        <tr><td>@j.Company</td><td>@j.Title</td><td>@j.Duration</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>
</div>

<div class="card mb-3">
    <div class="card-header"><strong>References</strong></div>
    <div class="card-body">
        @if (state.References.Count == 0)
        {
            <p class="text-muted">No references added.</p>
        }
        else
        {
            <table class="table table-sm">
                <thead><tr><th>Name</th><th>Relationship</th><th>Phone</th></tr></thead>
                <tbody>
                    @foreach (var r in state.References)
                    {
                        <tr><td>@r.Name</td><td>@r.Relationship</td><td>@r.Phone</td></tr>
                    }
                </tbody>
            </table>
        }
    </div>
</div>

<div class="d-flex gap-2">
    <a href="/apply/references" class="btn btn-outline-secondary">&larr; Back</a>
    <button class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@if (_submitted)
{
    <div class="alert alert-success mt-3">Your application has been submitted!</div>
}

@code {
    private bool _submitted;

    private string GetSessionId() =>
        HttpContextAccessor.HttpContext?.Request.Cookies[
            Services.WizardSessionMiddleware.CookieName] ?? string.Empty;

    private void Submit()
    {
        // In a real app, persist the application to a database here.
        _submitted = true;
    }
}

